function onLoad() {
	var showReopenComment = g_form.getValue('reopen_comments') + '' != '';

	g_form.setDisplay('reopen_comments', showReopenComment);

	// 2.8.5 | 2023-08-06 | mmcc | DFCT0012102 - Reopen comments are editable and should NOT when the task is in the 'Complete" state; added
	g_form.setReadOnly('reopen_comments', true);

}
